head.b:skin:
@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;800&family=Hind+Siliguri:wght@400;600;700&display=swap');

:root {
    --primary: #d4af37; /* Royal Gold */
    --primary-light: #fcf6ba;
    --bg-dark: #0a0e14; 
    --card-bg: rgba(22, 27, 34, 0.7);
    --text-white: #ffffff;
    --text-muted: #94a3b8;
    --border: rgba(212, 175, 55, 0.15);
    --glass: rgba(255, 255, 255, 0.03);
    --gradient-main: linear-gradient(135deg, #d4af37 0%, #fcf6ba 50%, #d4af37 100%);
}

* { box-sizing: border-box; scroll-behavior: smooth; }
body { 
    font-family: 'Plus Jakarta Sans', 'Hind Siliguri', sans-serif; 
    margin: 0; 
    background-color: var(--bg-dark); 
    color: var(--text-white); 
    overflow-x: hidden; 
    line-height: 1.6;
}

/* --- ANIMATED BACKGROUND --- */
.bg-pattern {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%; 
    background: 
        radial-gradient(circle at 20% 20%, rgba(212, 175, 55, 0.05) 0%, transparent 40%),
        radial-gradient(circle at 80% 80%, rgba(212, 175, 55, 0.05) 0%, transparent 40%);
    z-index: -1;
}

/* --- PREMIUM NAVBAR with increased width for one-line title --- */
header {
    position: fixed; top: 0; width: 100%; z-index: 1000;
    background: rgba(10, 14, 20, 0.8); 
    backdrop-filter: blur(20px);
    border-bottom: 1px solid var(--border);
    padding: 15px 5%; /* Increased padding for more space */
    display: flex; 
    justify-content: space-between; 
    align-items: center;
    gap: 20px; /* Add gap between logo and nav */
}
.logo-area { 
    display: flex; 
    align-items: center; 
    gap: 12px; 
    text-decoration: none; 
    flex-shrink: 1; /* Allow logo area to shrink if needed */
    min-width: 0; /* Enable truncation if necessary, but we want one line */
}
.logo-icon { 
    width: 48px; height: 48px; background: var(--gradient-main); 
    border-radius: 14px; display: flex; align-items: center; justify-content: center; 
    color: #000; font-weight: 800; font-size: 24px; 
    box-shadow: 0 5px 20px rgba(212, 175, 55, 0.3);
    transition: transform 0.3s; flex-shrink: 0;
}
.logo-area:hover .logo-icon { transform: rotate(-10deg) scale(1.1); }
.logo-text { 
    font-size: 26px; 
    font-weight: 800; 
    background: var(--gradient-main); 
    -webkit-background-clip: text; 
    -webkit-text-fill-color: transparent; 
    letter-spacing: 0.5px;
    white-space: nowrap; /* Force one line */
}

nav { 
    display: flex; 
    flex-wrap: wrap; 
    justify-content: flex-end; 
    flex-shrink: 0; /* Prevent nav from shrinking */
}
nav a { 
    margin-left: 25px; 
    text-decoration: none; 
    color: #cbd5e1; 
    font-weight: 600; 
    font-size: 15px; 
    transition: 0.3s; 
    position: relative; 
    white-space: nowrap; /* Keep nav items in one line */
}
nav a:hover { color: var(--primary); }
nav a::after { content: ''; position: absolute; bottom: -6px; left: 0; width: 0; height: 2px; background: var(--primary); transition: 0.3s; }
nav a:hover::after { width: 100%; }

/* Adjust for smaller screens - keep one line by allowing wrap */
@media (max-width: 1200px) {
    header { padding: 15px 4%; }
    .logo-text { font-size: 22px; }
    nav a { margin-left: 18px; font-size: 14px; }
}
@media (max-width: 992px) {
    .logo-text { font-size: 20px; }
    nav a { margin-left: 12px; font-size: 13px; }
}
@media (max-width: 768px) {
    header { padding: 12px 4%; }
    .logo-text { font-size: 18px; }
    nav { display: none; } /* Hide nav on mobile, can be replaced with hamburger later */
}

/* --- HERO SECTION --- */
.hero { 
    min-height: 100vh; display: flex; align-items: center; justify-content: center;
    text-align: center; 
    background: radial-gradient(circle at 50% 0%, #1a202c 0%, var(--bg-dark) 70%); 
    position: relative; padding: 100px 5%;
}
.hero-content { max-width: 800px; z-index: 1; animation: fadeInUp 1s ease-out; }

/* COMING SOON BADGE */
.coming-soon-badge { 
    display: inline-flex; align-items: center; gap: 10px;
    background: rgba(212, 175, 55, 0.1); 
    color: var(--primary); padding: 10px 25px; border-radius: 50px; 
    font-size: 14px; font-weight: 700; border: 1px solid var(--primary); 
    margin-bottom: 30px; text-transform: uppercase; letter-spacing: 2px;
    animation: glow 2s infinite alternate;
}
.coming-soon-badge span { width: 8px; height: 8px; background: var(--primary); border-radius: 50%; animation: blink 1s infinite; }

@keyframes blink { 0% { opacity: 0.2; } 50% { opacity: 1; } 100% { opacity: 0.2; } }
@keyframes glow { from { box-shadow: 0 0 5px rgba(212, 175, 55, 0.2); } to { box-shadow: 0 0 20px rgba(212, 175, 55, 0.4); } }
@keyframes fadeInUp { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }

.hero h1 { font-size: clamp(40px, 6vw, 70px); font-weight: 800; margin: 0 0 25px 0; line-height: 1.1; text-shadow: 0 10px 30px rgba(0,0,0,0.5); }
.hero h1 span { background: var(--gradient-main); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero p { font-size: 20px; color: var(--text-muted); margin-bottom: 40px; max-width: 600px; margin-left: auto; margin-right: auto; }

.btn-primary { 
    display: inline-block; background: var(--gradient-main); color: #000; 
    padding: 15px 40px; border-radius: 50px; text-decoration: none; 
    font-weight: 800; font-size: 16px; letter-spacing: 0.5px;
    box-shadow: 0 10px 30px rgba(212, 175, 55, 0.3);
    transition: transform 0.3s, box-shadow 0.3s;
}
.btn-primary:hover { transform: translateY(-3px); box-shadow: 0 15px 40px rgba(212, 175, 55, 0.5); }

/* --- SECTION STYLING --- */
.section-padding { padding: 120px 8%; position: relative; }
.section-header { text-align: center; margin-bottom: 70px; }
.section-header h2 { font-size: 42px; font-weight: 800; margin: 0 0 15px 0; }
.section-header h2 span { color: var(--primary); }
.section-header p { color: var(--text-muted); font-size: 18px; max-width: 600px; margin: 0 auto; }

/* --- SERVICE GRID (12 CARDS) --- */
.services-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 25px; }

.service-card { 
    background: var(--card-bg); padding: 30px; border-radius: 24px; 
    border: 1px solid rgba(255,255,255,0.05); 
    backdrop-filter: blur(10px);
    transition: 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    text-align: left; position: relative; overflow: hidden;
}
.service-card::before { 
    content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 3px; 
    background: var(--gradient-main); opacity: 0; transition: 0.3s; 
}
.service-card:hover { 
    border-color: rgba(212, 175, 55, 0.4); 
    transform: translateY(-10px); 
    box-shadow: 0 20px 50px rgba(0,0,0,0.5); 
}
.service-card:hover::before { opacity: 1; }

.icon-box { 
    width: 65px; height: 65px; background: rgba(212, 175, 55, 0.1); 
    color: var(--primary); border-radius: 18px; display: flex; 
    align-items: center; justify-content: center; font-size: 28px; margin-bottom: 20px;
    transition: 0.3s;
}
.service-card:hover .icon-box { background: var(--primary); color: #000; transform: rotate(-5deg); }

.service-card h3 { font-size: 20px; color: #fff; margin-bottom: 10px; }
.service-card p { color: var(--text-muted); font-size: 14px; margin-bottom: 20px; line-height: 1.6; }

.tags { display: flex; flex-wrap: wrap; gap: 6px; }
.tags span { 
    background: rgba(255,255,255,0.05); color: #aaa; 
    padding: 4px 10px; border-radius: 6px; font-size: 11px; 
    font-weight: 600; border: 1px solid rgba(255,255,255,0.08); 
}

/* --- FAQ SECTION (Expanded) --- */
.faq-section { background: #0d1117; }
.faq-container { max-width: 800px; margin: 0 auto; }

.faq-item { 
    background: var(--card-bg); margin-bottom: 15px; border-radius: 16px; 
    border: 1px solid rgba(255,255,255,0.05); overflow: hidden; transition: 0.3s;
}
.faq-item:hover { border-color: rgba(212, 175, 55, 0.2); }

.faq-question { 
    padding: 20px 25px; cursor: pointer; display: flex; 
    justify-content: space-between; align-items: center; 
    font-weight: 700; font-size: 17px; color: var(--text-white); 
}
.faq-icon { 
    font-size: 20px; color: var(--primary); transition: transform 0.3s; 
    font-weight: bold; display: flex; align-items: center; justify-content: center;
    width: 30px; height: 30px; border-radius: 50%; background: rgba(212, 175, 55, 0.1);
}

.faq-answer { 
    max-height: 0; overflow: hidden; transition: max-height 0.4s ease; 
    color: var(--text-muted); line-height: 1.7;
}
.faq-answer-content { padding: 0 25px 20px 25px; }

/* UI Logic for FAQ */
.faq-toggle { display: none; }
.faq-toggle:checked + .faq-question .faq-icon { transform: rotate(45deg); background: var(--primary); color: #000; }
.faq-toggle:checked ~ .faq-answer { max-height: 300px; padding: 0; border-top: 1px solid rgba(255,255,255,0.05); }

/* --- BLOG SECTION - GRID 4/8 + PAGINATION --- */
.blog-section { background: linear-gradient(180deg, #0a0e14 0%, #111827 100%); }
.blog-grid { 
    display: grid; 
    grid-template-columns: repeat(4, 1fr); 
    gap: 25px; 
    margin-bottom: 50px;
}
.post-card { 
    background: var(--card-bg); 
    border-radius: 20px; 
    overflow: hidden; 
    border: 1px solid rgba(255,255,255,0.05); 
    transition: 0.3s; 
    display: flex;
    flex-direction: column;
}
.post-card:hover { transform: translateY(-5px); box-shadow: 0 15px 30px rgba(0,0,0,0.3); }
.post-info { padding: 20px; flex-grow: 1; }
.post-info h3 { margin: 0 0 10px 0; font-size: 18px; line-height: 1.4; }
.post-info h3 a { color: #fff; text-decoration: none; }
.post-meta { font-size: 12px; color: var(--text-muted); margin-bottom: 12px; }
.read-more { color: var(--primary); font-weight: 700; text-decoration: none; font-size: 14px; display: inline-flex; align-items: center; gap: 5px; transition: 0.3s; }
.read-more:hover { gap: 10px; }

/* Pagination Styles */
.blog-pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 12px;
    margin-top: 40px;
}
.pagination-link, .pagination-current {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 45px;
    height: 45px;
    padding: 0 12px;
    background: var(--card-bg);
    border: 1px solid var(--border);
    border-radius: 12px;
    color: var(--text-white);
    text-decoration: none;
    font-weight: 600;
    transition: 0.3s;
    backdrop-filter: blur(5px);
}
.pagination-link:hover {
    background: var(--primary);
    color: #000;
    border-color: var(--primary);
    transform: scale(1.05);
}
.pagination-current {
    background: var(--primary);
    color: #000;
    border-color: var(--primary);
    cursor: default;
}
.pagination-dots {
    color: var(--text-muted);
    font-weight: 600;
}

/* Responsive for blog grid */
@media (max-width: 1200px) {
    .blog-grid { grid-template-columns: repeat(3, 1fr); }
}
@media (max-width: 900px) {
    .blog-grid { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 600px) {
    .blog-grid { grid-template-columns: 1fr; }
}

/* --- MAP SECTION --- */
.map-section {
    background: #0d1117;
    padding: 80px 8%;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
}
.map-container {
    max-width: 1200px;
    margin: 0 auto;
    border-radius: 30px;
    overflow: hidden;
    box-shadow: 0 20px 40px rgba(0,0,0,0.4);
    border: 1px solid var(--border);
}
.map-container iframe {
    width: 100%;
    height: 450px;
    display: block;
    border: 0;
}

/* --- STATS SECTION --- */
.stats-section {
    background: linear-gradient(145deg, #0a0e14 0%, #111111 100%);
    padding: 80px 8%;
}
.stats-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 30px;
    max-width: 1200px;
    margin: 0 auto;
}
.stat-card {
    text-align: center;
    padding: 30px 20px;
    background: var(--card-bg);
    border-radius: 24px;
    border: 1px solid var(--border);
    backdrop-filter: blur(10px);
    transition: 0.3s;
}
.stat-card:hover {
    transform: translateY(-8px);
    border-color: var(--primary);
}
.stat-number {
    font-size: 48px;
    font-weight: 800;
    background: var(--gradient-main);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    line-height: 1.2;
    margin-bottom: 8px;
}
.stat-label {
    color: var(--text-muted);
    font-size: 16px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1px;
}
@media (max-width: 800px) {
    .stats-grid { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 500px) {
    .stats-grid { grid-template-columns: 1fr; }
}

/* --- CTA SECTION --- */
.cta-section {
    padding: 100px 8%;
    background: radial-gradient(circle at 30% 30%, rgba(212, 175, 55, 0.1) 0%, transparent 60%);
    text-align: center;
}
.cta-content {
    max-width: 700px;
    margin: 0 auto;
}
.cta-content h2 {
    font-size: 42px;
    font-weight: 800;
    margin-bottom: 20px;
}
.cta-content p {
    color: var(--text-muted);
    font-size: 18px;
    margin-bottom: 30px;
}
.cta-buttons {
    display: flex;
    gap: 20px;
    justify-content: center;
    flex-wrap: wrap;
}
.btn-secondary {
    display: inline-block;
    background: transparent;
    color: var(--primary);
    padding: 15px 40px;
    border-radius: 50px;
    text-decoration: none;
    font-weight: 800;
    font-size: 16px;
    border: 2px solid var(--primary);
    transition: 0.3s;
}
.btn-secondary:hover {
    background: var(--primary);
    color: #000;
    transform: translateY(-3px);
}

/* --- CONTACT FORM SECTION (Styled Blogger Default) --- */
.contact-section {
    background: #0a0e14;
    padding: 80px 8%;
}
.contact-form-container {
    max-width: 700px;
    margin: 0 auto;
    background: var(--card-bg);
    border-radius: 30px;
    padding: 50px;
    border: 1px solid var(--border);
    backdrop-filter: blur(10px);
}
.contact-form-container .contact-form-widget {
    max-width: 100%;
}
.contact-form-container .contact-form-name,
.contact-form-container .contact-form-email,
.contact-form-container .contact-form-email-message {
    width: 100%;
    padding: 15px 20px;
    margin-bottom: 20px;
    background: rgba(255,255,255,0.05);
    border: 1px solid var(--border);
    border-radius: 16px;
    color: var(--text-white);
    font-family: inherit;
    font-size: 16px;
    transition: 0.3s;
}
.contact-form-container .contact-form-name:focus,
.contact-form-container .contact-form-email:focus,
.contact-form-container .contact-form-email-message:focus {
    outline: none;
    border-color: var(--primary);
    background: rgba(212, 175, 55, 0.1);
}
.contact-form-container .contact-form-button {
    background: var(--gradient-main);
    color: #000;
    padding: 15px 40px;
    border: none;
    border-radius: 50px;
    font-weight: 800;
    font-size: 16px;
    cursor: pointer;
    width: 100%;
    transition: 0.3s;
    text-transform: uppercase;
    letter-spacing: 1px;
}
.contact-form-container .contact-form-button:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 30px rgba(212, 175, 55, 0.4);
}
.contact-form-container .contact-form-error-message,
.contact-form-container .contact-form-success-message {
    color: var(--primary);
    margin-top: 15px;
    text-align: center;
}

/* --- BACK TO TOP BUTTON --- */
.back-to-top {
    position: fixed;
    bottom: 40px;
    right: 40px;
    width: 55px;
    height: 55px;
    background: var(--gradient-main);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #000;
    font-size: 24px;
    font-weight: bold;
    text-decoration: none;
    box-shadow: 0 5px 20px rgba(212, 175, 55, 0.3);
    transition: 0.3s;
    z-index: 99;
    border: 2px solid rgba(255,255,255,0.1);
}
.back-to-top:hover {
    transform: translateY(-10px) scale(1.1);
    box-shadow: 0 15px 40px rgba(212, 175, 55, 0.5);
}

/* --- FOOTER --- */
footer { background: #05070a; padding: 80px 8% 40px; border-top: 1px solid var(--border); }
.footer-content { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 40px; margin-bottom: 40px; }
.footer-col h4 { color: var(--primary); margin-bottom: 20px; font-size: 18px; }
.footer-col p, .footer-col a { color: var(--text-muted); text-decoration: none; display: block; margin-bottom: 10px; font-size: 15px; transition: 0.3s; }
.footer-col a:hover { color: #fff; padding-left: 5px; }
.map-link {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    color: var(--primary) !important;
    font-weight: 600;
}
.map-link:hover { color: #fff !important; }
.footer-bottom { text-align: center; padding-top: 30px; border-top: 1px solid rgba(255,255,255,0.05); font-size: 14px; color: var(--text-muted); }

/* POST VIEW & STATIC PAGE */
.post-view-container { 
    max-width: 1000px; /* Increased width for better readability */
    margin: 120px auto 60px; 
    padding: 0 30px; 
}
.post-body-content { 
    background: var(--card-bg); 
    padding: 40px; 
    border-radius: 30px; 
    border: 1px solid var(--border); 
    line-height: 1.8; 
    color: #e2e8f0; 
}

/* Back to Home Button */
.back-home-container {
    text-align: center;
    margin: 40px 0 20px;
}
.back-home-btn {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    background: var(--card-bg);
    color: var(--primary);
    padding: 12px 30px;
    border-radius: 50px;
    text-decoration: none;
    font-weight: 700;
    font-size: 16px;
    border: 1px solid var(--border);
    transition: 0.3s;
}
.back-home-btn:hover {
    background: var(--primary);
    color: #000;
    transform: translateY(-3px);
    box-shadow: 0 10px 20px rgba(212, 175, 55, 0.2);
}

/* Comments Section Styling */
.comments { 
    margin-top: 50px; 
    background: var(--card-bg);
    border-radius: 30px;
    padding: 30px;
    border: 1px solid var(--border);
}
.comments h4 { 
    color: var(--primary); 
    font-size: 24px;
    margin-bottom: 30px;
    text-align: center;
}
.comment-footer { margin-top: 20px; }
#comments-block dt { color: var(--primary); font-weight: 700; }
#comments-block dd { margin-left: 20px; color: var(--text-muted); }
.comment-timestamp a { color: var(--text-muted); font-size: 12px; }

/* MOBILE RESPONSIVE */
@media (max-width: 768px) {
    header { padding: 12px 4%; }
    .logo-text { font-size: 18px; }
    nav { display: none; }
    .hero h1 { font-size: 36px; }
    .section-padding { padding: 60px 5%; }
    .services-grid { grid-template-columns: 1fr; }
    .cta-content h2 { font-size: 32px; }
    .map-container iframe { height: 300px; }
    .contact-form-container { padding: 30px 20px; }
    .back-to-top { bottom: 20px; right: 20px; width: 45px; height: 45px; font-size: 20px; }
    .post-view-container { padding: 0 20px; }
}
